cd /workspace/valkey && mkdir -p tests/tmp && cat > tests/tmp/slot-migration-repro.tcl <<'EOF'
proc get_open_slots {srv_idx} {
    set slots [dict get [cluster_get_myself $srv_idx] slots]
    if {[regexp {\[.*} $slots slots]} {
        set slots [regsub -all {[{}]} $slots ""]
        return $slots
    } else {
        return {}
    }
}

proc wait_for_slot_state {srv_idx pattern} {
    wait_for_condition 100 50 {
        [get_open_slots $srv_idx] eq $pattern
    } else {
        fail "incorrect slot state on R $srv_idx: expected $pattern; got [get_open_slots $srv_idx]"
    }
}

start_cluster 3 3 {tags {external:skip cluster} overrides {cluster-allow-replica-migration no cluster-node-timeout 1000 cluster-ping-interval 300000}} {
    test "stale importing source after source shard failover packet ordering" {
        set R0_id [R 0 CLUSTER MYID]
        set R1_id [R 1 CLUSTER MYID]
        set R3_id [R 3 CLUSTER MYID]

        assert_equal {OK} [R 0 CLUSTER SETSLOT 609 MIGRATING $R1_id]
        assert_equal {OK} [R 1 CLUSTER SETSLOT 609 IMPORTING $R0_id]
        wait_for_slot_state 1 "\[609-<-$R0_id\]"

        # Force R1 to hear the old source (R0) announce its replica role before
        # it can hear the new source primary (R3) announce ownership directly.
        R 1 debug disable-cluster-reconnection 1
        R 3 debug disable-cluster-reconnection 1
        R 1 debug clusterlink kill all $R3_id
        R 3 debug clusterlink kill all $R1_id

        R 3 cluster failover takeover
        wait_for_condition 1000 10 {
            [s 0 role] eq {slave} && [s -3 role] eq {master} &&
            [cluster_has_flag [cluster_get_node_by_id 1 $R0_id] slave] eq 1 &&
            [cluster_has_flag [cluster_get_node_by_id 1 $R3_id] master] eq 1
        } else {
            puts [R 1 cluster nodes]
            fail "R1 did not process R0 replica role before R3 reconnection"
        }

        # The importing source should move from old source R0 to new source R3.
        assert_equal "\[609-<-$R3_id\]" [get_open_slots 1]

        R 1 debug disable-cluster-reconnection 0
        R 3 debug disable-cluster-reconnection 0
    }
}
EOF
./runtest --single tmp/slot-migration-repro --verbose --dump-logs

