action.old_str:
/* Transfer slots from `from_node` to `to_node`.
 *
 * Iterates over all cluster slots, transferring each slot covered
 * by `from_node` to `to_node`. Counts and returns the number of
 * slots transferred. */
int clusterMoveNodeSlots(clusterNode *from_node, clusterNode *to_node) {
    int processed = 0;
    for (int j = 0; j < CLUSTER_SLOTS; j++) {
        if (clusterNodeCoversSlot(from_node, j)) {
            clusterDelSlot(j);
            clusterAddSlot(to_node, j);
            processed++;
        }
    }
    return processed;
}

action.new_str:
/* Transfer slots and open-slot migration endpoints from `from_node` to `to_node`.
 *
 * This is used when `from_node` is observed becoming a replica of `to_node`
 * after a same-shard failover. Slot ownership and any importing/migrating
 * references to the old primary must move together so observers never keep
 * stale migration endpoints while already treating the new primary as owner. */
int clusterMoveNodeSlots(clusterNode *from_node, clusterNode *to_node) {
    int processed = 0;
    for (int j = 0; j < CLUSTER_SLOTS; j++) {
        if (server.cluster->migrating_slots_to[j] == from_node) server.cluster->migrating_slots_to[j] = to_node;
        if (server.cluster->importing_slots_from[j] == from_node) server.cluster->importing_slots_from[j] = to_node;

        if (clusterNodeCoversSlot(from_node, j)) {
            clusterDelSlot(j);
            clusterAddSlot(to_node, j);
            processed++;
        }
    }
    return processed;
}

