    static const char *help[] = {"CLUSTERLINK KILL <to|from|all> <node-id>",
                                 "    Kills the link based on the direction to/from (both) with the provided node.",
                                 NULL};

    return help;
}

char *clusterNodeGetShardId(clusterNode *node) {
